{
  "sentences": [
    {
      "text": "今天天氣有點熱，我有點累。",
      "pinyin": "Jīntiān tiānqì yǒudiǎn rè, wǒ yǒudiǎn lèi.",
      "pinyin_numeric": "jin1tian1 tian1qi4 you3dian3 re4, wo3 you3dian3 lei4.",
      "translation_en": "The weather is a bit hot today, and I'm a little tired.",
      "translation_ko": "오늘 날씨가 좀 덥고, 저는 조금 피곤해요."
    },
    {
      "text": "下雨了，我有點不開心。",
      "pinyin": "Xià yǔ le, wǒ yǒudiǎn bù kāixīn.",
      "pinyin_numeric": "xia4 yu3 le0, wo3 you3dian3 bu4 kai1xin1.",
      "translation_en": "It's raining, and I'm a little unhappy.",
      "translation_ko": "비가 와서, 저는 좀 기분이 안 좋아요."
    },
    {
      "text": "今天陰天，我的心情有點不好。",
      "pinyin": "Jīntiān yīntiān, wǒ de xīnqíng yǒudiǎn bù hǎo.",
      "pinyin_numeric": "jin1tian1 yin1tian1, wo3 de0 xin1qing2 you3dian3 bu4 hao3.",
      "translation_en": "It's cloudy today, and my mood is a bit bad.",
      "translation_ko": "오늘은 흐린 날씨라서, 제 기분이 좀 안 좋아요."
    },
    {
      "text": "颱風要來了，我有點緊張。",
      "pinyin": "Táifēng yào lái le, wǒ yǒudiǎn jǐnzhāng.",
      "pinyin_numeric": "tai2feng1 yao4 lai2 le0, wo3 you3dian3 jin3zhang1.",
      "translation_en": "A typhoon is coming, and I'm a bit nervous.",
      "translation_ko": "태풍이 오려고 해서, 저는 좀 긴장돼요."
    },
    {
      "text": "今天三十度，天氣有點悶熱。",
      "pinyin": "Jīntiān sānshí dù, tiānqì yǒudiǎn mēnrè.",
      "pinyin_numeric": "jin1tian1 san1shi2 du4, tian1qi4 you3dian3 men1re4.",
      "translation_en": "It's 30 degrees today, and the weather is a bit muggy.",
      "translation_ko": "오늘은 30도라서, 날씨가 좀 후덥지근해요."
    },
    {
      "text": "出太陽了，我的心情有點開心。",
      "pinyin": "Chū tàiyáng le, wǒ de xīnqíng yǒudiǎn kāixīn.",
      "pinyin_numeric": "chu1 tai4yang2 le0, wo3 de0 xin1qing2 you3dian3 kai1xin1.",
      "translation_en": "The sun came out, and my mood is a bit happy.",
      "translation_ko": "해가 나서, 제 기분이 좀 좋아요."
    },
    {
      "text": "今天很涼快，我有點想出去走走。",
      "pinyin": "Jīntiān hěn liángkuai, wǒ yǒudiǎn xiǎng chūqù zǒu zǒu.",
      "pinyin_numeric": "jin1tian1 hen3 liang2kuai5, wo3 you3dian3 xiang3 chu1qu4 zou3 zou3.",
      "translation_en": "It's very cool today, and I kind of want to go out for a walk.",
      "translation_ko": "오늘은 시원해서, 저는 좀 나가서 산책하고 싶어요."
    },
    {
      "text": "下雨了，路有點滑，要小心。",
      "pinyin": "Xià yǔ le, lù yǒudiǎn huá, yào xiǎoxīn.",
      "pinyin_numeric": "xia4 yu3 le0, lu4 you3dian3 hua2, yao4 xiao3xin1.",
      "translation_en": "It's raining, the road is a bit slippery, so be careful.",
      "translation_ko": "비가 와서 길이 좀 미끄러우니 조심하세요."
    },
    {
      "text": "今天天氣很好，我有點有精神。",
      "pinyin": "Jīntiān tiānqì hěn hǎo, wǒ yǒudiǎn yǒu jīngshén.",
      "pinyin_numeric": "jin1tian1 tian1qi4 hen3 hao3, wo3 you3dian3 you3 jing1shen2.",
      "translation_en": "The weather is nice today, and I feel a bit energetic.",
      "translation_ko": "오늘 날씨가 좋아서, 저는 좀 활기차요."
    },
    {
      "text": "颱風天，我有點擔心。",
      "pinyin": "Táifēng tiān, wǒ yǒudiǎn dānxīn.",
      "pinyin_numeric": "tai2feng1 tian1, wo3 you3dian3 dan1xin1.",
      "translation_en": "On a typhoon day, I'm a bit worried.",
      "translation_ko": "태풍이 오는 날이라서, 저는 좀 걱정돼요."
    }
  ]
}
